fn as_scheduled(&self) -> Option<&TxScheduled> { None }
fn as_async_commitment(&self) -> Option<&TxAsyncCommitment> { None }
fn as_async_settlement(&self) -> Option<&TxAsyncSettlement> { None }
fn signature(&self) -> Signature;

fn as_scheduled(&self) -> Option<&TxScheduled> {
    match self {
        Self::Scheduled(tx) => Some(tx.tx()),
        _ => None,
    }
}

if let Self::Scheduled(_) = self { return Ok(SYSTEM_SENDER); }
if let Self::AsyncCommitment(_) = self { return Ok(ASYNC_COMMITMENT_SYSTEM_SENDER); }
if let Self::AsyncSettlement(_) = self { return Ok(ASYNC_SETTLEMENT_SYSTEM_SENDER); }

if let Self::Passkey(tx) = self {
    match tx.signature() {
        PasskeySignature::Secp256k1(sig) => { ... }
        PasskeySignature::P256(p256_sig) => { verify_p256_signature(...)?; return Ok(p256_sig.recover_address()); }
        PasskeySignature::WebAuthn(webauthn_sig) => { verify_webauthn_signature(...)?; return Ok(webauthn_sig.recover_address()); }
    }
}

impl SignedTransaction for OpPooledTransaction {
    fn signature(&self) -> Signature { ... }
}

impl SignedTransaction for OpTxEnvelope {
    fn signature(&self) -> Signature {
        match self {
            Self::Deposit(_) => Signature::new(U256::ZERO, U256::ZERO, false),
            ...
        }
    }
}
